#!/usr/bin/env python3
"""Run this once to deploy the new Mentora logo and favicon."""
import base64, os

BASE = os.path.expanduser(
    "~/Desktop/demo/flask-app 2/dental-academy-clean/static"
)

DATA = {
    "favicon.ico": "",
    "favicon.png": "",
    "favicon_192.png": "",
    "logo.png": "",
}

TARGETS = {
    "favicon.ico":    os.path.join(BASE, "favicon.ico"),
    "favicon.png":    os.path.join(BASE, "favicon.png"),
    "favicon_192.png": os.path.join(BASE, "images", "favicon.png"),
    "logo.png":       os.path.join(BASE, "images", "logo.png"),
}

for name, b64 in DATA.items():
    dst = TARGETS[name]
    with open(dst, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"✓  {os.path.basename(dst)}  ({os.path.getsize(dst)} bytes)")

print("\nDone! Refresh your browser to see the new logo.")
